function buildBaseQuery(queryParams) {
  const queryType = Object.keys(queryParams)[0];
  return { [queryType]: queryParams[queryType] };
}

function buildFilters(filters) {
  return filters.map((filter) => {
    switch (filter.type) {
      case 'term':
        return { term: { [filter.field]: filter.value } };
      case 'terms':
        return { terms: { [filter.field]: filter.value } };
      case 'range':
        return { range: { [filter.field]: filter.config || filter.value } };
      case 'exists':
        return { exists: { field: filter.field } };
      case 'bool':
        return { bool: filter.config };
      case 'geo_distance':
        return {
          geo_distance: {
            distance: filter.config.distance,
            [filter.field]: filter.config.location,
          },
        };
      case 'nested':
        return {
          nested: {
            path: filter.config.path,
            query: filter.config.query,
            score_mode: filter.config.score_mode || 'avg',
          },
        };
      default:
        throw new Error(`Unsupported filter type: ${filter.type}`);
    }
  });
}

function buildAggregations(aggregations) {
  const aggs = {};
  for (const [name, aggDef] of Object.entries(aggregations)) {
    const aggBody = {};
    const aggConfig = { ...(aggDef.config || {}) };

    if (aggDef.field) {
      aggConfig.field = aggDef.field;
    }

    aggBody[aggDef.type] = aggConfig;

    if (aggDef.sub_aggregations) {
      aggBody.aggs = buildAggregations(aggDef.sub_aggregations);
    }

    aggs[name] = aggBody;
  }
  return aggs;
}

function buildScriptScoreQuery(baseQuery, scoring) {
  const scriptScoreQuery = {
    script_score: {
      query: baseQuery,
      script: {
        source: scoring.script_source,
        lang: scoring.lang || 'painless',
      },
    },
  };

  if (scoring.params && Object.keys(scoring.params).length > 0) {
    scriptScoreQuery.script_score.script.params = scoring.params;
  }

  if (scoring.max_boost) {
    scriptScoreQuery.script_score.max_boost = scoring.max_boost;
  }

  if (scoring.boost_mode) {
    scriptScoreQuery.script_score.boost_mode = scoring.boost_mode;
  }

  return scriptScoreQuery;
}

function buildElasticsearchQuery(params) {
  let baseQuery = buildBaseQuery(params.query);

  // Apply filters using bool query wrapper
  if (params.filters && params.filters.length > 0) {
    const filterClauses = buildFilters(params.filters);
    baseQuery = {
      bool: {
        must: [baseQuery],
        filter: filterClauses,
      },
    };
  }

  // Apply script scoring if provided
  let finalQuery;
  if (params.scoring) {
    finalQuery = buildScriptScoreQuery(baseQuery, params.scoring);
  } else {
    finalQuery = baseQuery;
  }

  const esQuery = {
    query: finalQuery,
    from: params.from || 0,
    size: params.size !== undefined ? params.size : 10,
  };

  if (params.sort) {
    esQuery.sort = params.sort;
  }

  if (params.highlight) {
    esQuery.highlight = params.highlight;
  }

  if (params.source !== undefined) {
    esQuery._source = params.source;
  }

  if (params.aggregations) {
    esQuery.aggs = buildAggregations(params.aggregations);
  }

  if (params.collapse) {
    esQuery.collapse = params.collapse;
  }

  if (params.search_after) {
    esQuery.search_after = params.search_after;
  }

  if (params.track_total_hits !== undefined) {
    esQuery.track_total_hits = params.track_total_hits;
  }

  if (params.scoring && params.scoring.min_score) {
    esQuery.min_score = params.scoring.min_score;
  }

  return esQuery;
}

