// Main search endpoint
app.post('/api/search', async (req, res) => {
  try {
    // Validate input
    const { error, value: params } = searchParamsSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      return res.status(400).json({
        status: 'error',
        message: 'Validation failed',
        details: error.details.map((d) => ({
          field: d.path.join('.'),
          message: d.message,
        })),
      });
    }

    // Validate custom scoring script if provided
    if (params.scoring) {
      const scriptValidation = validateScript(params.scoring.script_source);
      if (!scriptValidation.valid) {
        return res.status(400).json({
          status: 'error',
          message: 'Script validation failed',
          reason: scriptValidation.reason,
        });
      }
    }

    // Build the Elasticsearch query
    const esQuery = buildElasticsearchQuery(params);

    console.log('Executing Elasticsearch query:', JSON.stringify(esQuery, null, 2));

    // Execute the search
    const result = await esClient.search({
      index: params.index,
      body: esQuery,
    });

    const response = {
      status: 'success',
      took: result.took,
      timed_out: result.timed_out,
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map((hit) => ({
        _index: hit._index,
        _id: hit._id,
        _score: hit._score,
        _source: hit._source,
        highlight: hit.highlight || undefined,
        sort: hit.sort || undefined,
        inner_hits: hit.inner_hits || undefined,
      })),
    };

    if (result.aggregations) {
      response.aggregations = result.aggregations;
    }

    res.json(response);
  } catch (err) {
    console.error('Search error:', err);

    if (err.meta && err.meta.body) {
      return res.status(err.meta.statusCode || 500).json({
        status: 'error',
        message: 'Elasticsearch query failed',
        details: err.meta.body.error,
      });
    }

    res.status(500).json({
      status: 'error',
      message: 'Internal server error',
      error: err.message,
    });
  }
});

